// Static FRI vectors captured from loom commit e58fe2fb0255.
// These are not regenerated by verifier-ray/testdata/generate because loom's
// reference FRI pieces currently live under Go internal/ packages.

pub const LoomLeafHashCase = struct { base_pairs: []const [2]u32, ext_pairs: []const [2][6]u32, expected: [8]u32 };
pub const LoomNodeHashCase = struct { left: [8]u32, right: [8]u32, expected: [8]u32 };
pub const LoomMerkleCase = struct { leaf_idx: u32, leaf: [8]u32, siblings: []const [8]u32, root: [8]u32 };
pub const LoomNamedTranscriptCase = struct { first_name: []const u8, first_bindings: []const u32, first_expected: [8]u32, second_name: []const u8, second_bindings: []const u32, second_expected: [8]u32, second_ext_expected: [6]u32 };
pub const LoomPowTranscriptCase = struct { name: []const u8, bindings: []const u32, nb_bits: u32, salt: u32, expected: [8]u32 };
pub const LoomDeepAlphaCase = struct { zeta_bindings: []const u32, zeta_digest: [8]u32, alpha_digest: [8]u32, alpha_ext: [6]u32 };
pub const LoomFriBasePath = struct { leaf_idx: u32, siblings: []const [8]u32 };
pub const LoomFriBaseLayer = struct { leaf_p_base: u32, leaf_q_base: u32, path: LoomFriBasePath };
pub const LoomFriBaseQuery = struct { layers: []const LoomFriBaseLayer };
pub const LoomFriBaseProofCase = struct {
    n: u32,
    d: u32,
    num_queries: u32,
    num_rounds: u32,
    query_positions: []const u32,
    level_ds: []const u32,
    level_roots: []const [8]u32,
    fri_roots: []const [8]u32,
    final_poly_base: []const u32,
    queries: []const LoomFriBaseQuery,
    level_queries: []const []const LoomFriBaseLayer,
};
pub const LoomFriExtLayer = struct { leaf_p_ext: [6]u32, leaf_q_ext: [6]u32, path: LoomFriBasePath };
pub const LoomFriExtQuery = struct { layers: []const LoomFriExtLayer };
pub const LoomFriExtProofCase = struct {
    n: u32,
    d: u32,
    num_queries: u32,
    num_rounds: u32,
    query_positions: []const u32,
    level_ds: []const u32,
    level_roots: []const [8]u32,
    fri_roots: []const [8]u32,
    final_poly_ext: []const [6]u32,
    queries: []const LoomFriExtQuery,
    level_queries: []const []const LoomFriExtLayer,
};
pub const LoomBridgeRail = enum { base, ext };
pub const LoomBridgeSlot = struct { name: []const u8, tree_idx: u32, poly_idx: u32, rail: LoomBridgeRail };
pub const LoomBridgeValue = struct { name: []const u8, value: [6]u32 };
pub const LoomBridgeSampling = struct {
    leaf_idx: u32,
    base_pairs: []const [2]u32 = &.{},
    ext_pairs: []const [2][6]u32 = &.{},
};
pub const LoomBridgeLayer = struct { leaf_idx: u32, leaf_p_ext: [6]u32, leaf_q_ext: [6]u32 };
pub const LoomBridgeQuery = struct {
    position: u32,
    point_samplings: []const LoomBridgeSampling,
    fri_layer: LoomBridgeLayer,
    level_layers: []const LoomBridgeLayer,
};
pub const LoomBridgeCase = struct {
    sizes: []const u32,
    tree_sizes: []const u32,
    zeta: [6]u32,
    alpha: [6]u32,
    eval_points: []const []const [6]u32,
    column_names: []const []const []const []const u8,
    column_keys: []const []const []const []const u8,
    air_chunks: []const []const []const u8,
    values_at_zeta: []const LoomBridgeValue,
    col_slots: []const LoomBridgeSlot,
    air_chunk_slots: []const LoomBridgeSlot,
    queries: []const LoomBridgeQuery,
};

